{
  "name": "Stockify",
  "description": "An intuitive, modern platform for businesses to track inventory, manage suppliers, and monitor stock health in real-time."
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  category: string;
  price: number;
  quantity: number;
  minThreshold: number;
  supplier: string;
  imageUrl: string;
  lastUpdated: string;
}

export interface StockContextType {
  products: Product[];
  addProduct: (product: Omit<Product, 'id' | 'lastUpdated'>) => void;
  updateProduct: (id: string, product: Partial<Product>) => void;
  deleteProduct: (id: string) => void;
  stats: {
    totalValue: number;
    lowStockCount: number;
    totalItems: number;
    categoriesCount: number;
  };
}

export interface AppConfig {
  appName: string;
  currency: string;
  themeColor: string;
  companyName: string;
  socialLinks: {
    twitter: string;
    linkedin: string;
    website: string;
  };
}

export enum ViewState {
  DASHBOARD = 'DASHBOARD',
  INVENTORY = 'INVENTORY',
  SETTINGS = 'SETTINGS'
}

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { Product, StockContextType } from '../types';
import { MOCK_PRODUCTS } from '../constants';

const StockContext = createContext<StockContextType | undefined>(undefined);

export const StockProvider = ({ children }: { children: ReactNode }) => {
  // Initialize with mock data
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('stockify_products');
    return saved ? JSON.parse(saved) : MOCK_PRODUCTS;
  });

  // Persist to local storage
  useEffect(() => {
    localStorage.setItem('stockify_products', JSON.stringify(products));
  }, [products]);

  const addProduct = (newProductData: Omit<Product, 'id' | 'lastUpdated'>) => {
    const newProduct: Product = {
      ...newProductData,
      id: Math.random().toString(36).substr(2, 9),
      lastUpdated: new Date().toISOString()
    };
    setProducts(prev => [newProduct, ...prev]);
  };

  const updateProduct = (id: string, updates: Partial<Product>) => {
    setProducts(prev => prev.map(p => 
      p.id === id ? { ...p, ...updates, lastUpdated: new Date().toISOString() } : p
    ));
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const stats = useMemo(() => {
    return {
      totalValue: products.reduce((acc, curr) => acc + (curr.price * curr.quantity), 0),
      lowStockCount: products.filter(p => p.quantity <= p.minThreshold).length,
      totalItems: products.reduce((acc, curr) => acc + curr.quantity, 0),
      categoriesCount: new Set(products.map(p => p.category)).size
    };
  }, [products]);

  return (
    <StockContext.Provider value={{ products, addProduct, updateProduct, deleteProduct, stats }}>
      {children}
    </StockContext.Provider>
  );
};

export const useStock = () => {
  const context = useContext(StockContext);
  if (context === undefined) {
    throw new Error('useStock must be used within a StockProvider');
  }
  return context;
};

import React from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, Legend 
} from 'recharts';
import { useStock } from '../contexts/StockContext';
import { APP_CONFIG } from '../constants';
import { DollarSign, AlertTriangle, Package, TrendingUp } from 'lucide-react';

const KPICard = ({ title, value, icon: Icon, trend, alert }: any) => (
  <div className={`bg-white p-6 rounded-xl shadow-sm border border-slate-100 relative overflow-hidden group hover:shadow-md transition-all`}>
    <div className="flex justify-between items-start">
      <div>
        <p className="text-slate-500 text-sm font-medium mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-slate-900">{value}</h3>
      </div>
      <div className={`p-3 rounded-lg ${alert ? 'bg-red-50 text-red-600' : 'bg-brand-50 text-brand-600'}`}>
        <Icon size={24} />
      </div>
    </div>
    {trend && (
      <div className="mt-4 flex items-center text-sm text-green-600">
        <TrendingUp size={16} className="mr-1" />
        <span>{trend} vs last month</span>
      </div>
    )}
  </div>
);

const Dashboard = () => {
  const { products, stats } = useStock();

  // Prepare data for charts
  const categoryData = products.reduce((acc: any[], curr) => {
    const existing = acc.find(item => item.name === curr.category);
    if (existing) {
      existing.value += curr.quantity;
    } else {
      acc.push({ name: curr.category, value: curr.quantity });
    }
    return acc;
  }, []);

  const lowStockData = products
    .filter(p => p.quantity <= p.minThreshold * 1.5) // Show items near threshold
    .map(p => ({
      name: p.name.substring(0, 15) + '...',
      stock: p.quantity,
      threshold: p.minThreshold
    }))
    .slice(0, 7);

  const COLORS = ['#0284c7', '#0ea5e9', '#38bdf8', '#7dd3fc', '#bae6fd'];

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Dashboard Overview</h2>
        <span className="text-sm text-slate-500">Last updated: {new Date().toLocaleDateString()}</span>
      </div>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <KPICard 
          title="Total Stock Value" 
          value={`${APP_CONFIG.currency}${stats.totalValue.toLocaleString()}`} 
          icon={DollarSign}
          trend="+12%"
        />
        <KPICard 
          title="Low Stock Alerts" 
          value={stats.lowStockCount} 
          icon={AlertTriangle} 
          alert={stats.lowStockCount > 0}
        />
        <KPICard 
          title="Total Items" 
          value={stats.totalItems} 
          icon={Package} 
        />
        <KPICard 
          title="Active Categories" 
          value={stats.categoriesCount} 
          icon={TrendingUp} 
        />
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mt-8">
        {/* Inventory Distribution */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Inventory by Category</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Low Stock Watchlist */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-semibold text-slate-800 mb-4">Stock Levels Monitor</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={lowStockData} layout="vertical" margin={{ left: 20 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                <XAxis type="number" />
                <YAxis dataKey="name" type="category" width={100} style={{ fontSize: '12px' }} />
                <Tooltip cursor={{fill: '#f0f9ff'}} />
                <Legend />
                <Bar dataKey="stock" fill="#0ea5e9" name="Current Stock" radius={[0, 4, 4, 0]} />
                <Bar dataKey="threshold" fill="#ef4444" name="Min Threshold" radius={[0, 4, 4, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { useStock } from '../contexts/StockContext';
import { APP_CONFIG, CATEGORIES } from '../constants';
import { Product } from '../types';
import { 
  Search, Plus, Filter, Trash2, Edit2, AlertCircle, CheckCircle, 
  MoreVertical, ChevronLeft, ChevronRight, FileDown 
} from 'lucide-react';
import ProductModal from './ProductModal';

const InventoryTable = () => {
  const { products, deleteProduct, updateProduct } = useStock();
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | undefined>(undefined);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 8;

  // Filter Logic
  const filteredProducts = useMemo(() => {
    return products.filter(product => {
      const matchesSearch = product.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                            product.sku.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = categoryFilter === 'All' || product.category === categoryFilter;
      return matchesSearch && matchesCategory;
    });
  }, [products, searchTerm, categoryFilter]);

  // Pagination Logic
  const totalPages = Math.ceil(filteredProducts.length / itemsPerPage);
  const currentData = filteredProducts.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  const handleEdit = (product: Product) => {
    setEditingProduct(product);
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this item?')) {
      deleteProduct(id);
    }
  };

  const handleQuickUpdate = (id: string, currentQty: number, change: number) => {
    const newQty = Math.max(0, currentQty + change);
    updateProduct(id, { quantity: newQty });
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-800">Inventory Management</h2>
        <div className="flex gap-2">
          <button className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors">
            <FileDown size={18} />
            <span className="hidden sm:inline">Export</span>
          </button>
          <button 
            onClick={() => { setEditingProduct(undefined); setIsModalOpen(true); }}
            className="flex items-center gap-2 px-4 py-2 bg-brand-600 text-white rounded-lg hover:bg-brand-700 transition-colors shadow-sm"
          >
            <Plus size={18} />
            <span>Add Item</span>
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Search by name or SKU..." 
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-brand-500 focus:border-transparent"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="relative w-full md:w-64">
          <Filter className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
          <select 
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-brand-500 appearance-none bg-white"
            value={categoryFilter}
            onChange={(e) => setCategoryFilter(e.target.value)}
          >
            <option value="All">All Categories</option>
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 text-slate-600 text-sm font-semibold uppercase tracking-wider">
                <th className="p-4 border-b border-slate-100">Product</th>
                <th className="p-4 border-b border-slate-100">SKU</th>
                <th className="p-4 border-b border-slate-100">Category</th>
                <th className="p-4 border-b border-slate-100">Price</th>
                <th className="p-4 border-b border-slate-100">Status</th>
                <th className="p-4 border-b border-slate-100">Qty</th>
                <th className="p-4 border-b border-slate-100 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {currentData.length > 0 ? (
                currentData.map((product) => (
                  <tr key={product.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="p-4">
                      <div className="flex items-center gap-3">
                        <img 
                          src={product.imageUrl} 
                          alt={product.name} 
                          className="w-10 h-10 rounded-lg object-cover bg-slate-200"
                        />
                        <div>
                          <p className="font-medium text-slate-900">{product.name}</p>
                          <p className="text-xs text-slate-500">{product.supplier}</p>
                        </div>
                      </div>
                    </td>
                    <td className="p-4 text-sm text-slate-600 font-mono">{product.sku}</td>
                    <td className="p-4 text-sm text-slate-600">
                      <span className="px-2 py-1 rounded-full bg-slate-100 text-xs font-medium">
                        {product.category}
                      </span>
                    </td>
                    <td className="p-4 text-sm font-medium text-slate-900">
                      {APP_CONFIG.currency}{product.price.toFixed(2)}
                    </td>
                    <td className="p-4">
                      {product.quantity <= product.minThreshold ? (
                        <div className="flex items-center gap-1 text-red-600 text-sm font-medium px-2 py-1 bg-red-50 rounded-full w-fit">
                          <AlertCircle size={14} />
                          <span>Low Stock</span>
                        </div>
                      ) : (
                        <div className="flex items-center gap-1 text-emerald-600 text-sm font-medium px-2 py-1 bg-emerald-50 rounded-full w-fit">
                          <CheckCircle size={14} />
                          <span>In Stock</span>
                        </div>
                      )}
                    </td>
                    <td className="p-4">
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleQuickUpdate(product.id, product.quantity, -1)}
                          className="w-6 h-6 rounded bg-slate-100 hover:bg-slate-200 flex items-center justify-center text-slate-600 transition-colors"
                        >
                          -
                        </button>
                        <span className="w-8 text-center font-medium text-slate-700">{product.quantity}</span>
                        <button 
                          onClick={() => handleQuickUpdate(product.id, product.quantity, 1)}
                          className="w-6 h-6 rounded bg-slate-100 hover:bg-slate-200 flex items-center justify-center text-slate-600 transition-colors"
                        >
                          +
                        </button>
                      </div>
                    </td>
                    <td className="p-4 text-right">
                      <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => handleEdit(product)}
                          className="p-2 text-slate-400 hover:text-brand-600 hover:bg-brand-50 rounded-lg transition-colors"
                        >
                          <Edit2 size={18} />
                        </button>
                        <button 
                          onClick={() => handleDelete(product.id)}
                          className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={7} className="p-8 text-center text-slate-500">
                    No items found matching your search.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        <div className="p-4 border-t border-slate-100 flex justify-between items-center">
          <span className="text-sm text-slate-500">
            Showing {Math.min(filteredProducts.length, (currentPage - 1) * itemsPerPage + 1)} to {Math.min(filteredProducts.length, currentPage * itemsPerPage)} of {filteredProducts.length} entries
          </span>
          <div className="flex gap-2">
            <button 
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
              className="p-2 rounded-lg border border-slate-200 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <ChevronLeft size={16} />
            </button>
            <button 
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages}
              className="p-2 rounded-lg border border-slate-200 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              <ChevronRight size={16} />
            </button>
          </div>
        </div>
      </div>

      {isModalOpen && (
        <ProductModal 
          isOpen={isModalOpen} 
          onClose={() => setIsModalOpen(false)} 
          initialData={editingProduct} 
        />
      )}
    </div>
  );
};

export default InventoryTable;

import React, { useState, useEffect } from 'react';
import { Product } from '../types';
import { CATEGORIES } from '../constants';
import { useStock } from '../contexts/StockContext';
import { X, Save, Upload } from 'lucide-react';

interface ProductModalProps {
  isOpen: boolean;
  onClose: () => void;
  initialData?: Product;
}

const ProductModal: React.FC<ProductModalProps> = ({ isOpen, onClose, initialData }) => {
  const { addProduct, updateProduct } = useStock();

  const [formData, setFormData] = useState<Partial<Product>>({
    name: '',
    sku: '',
    category: CATEGORIES[0],
    price: 0,
    quantity: 0,
    minThreshold: 10,
    supplier: '',
    imageUrl: 'https://picsum.photos/200/200'
  });

  useEffect(() => {
    if (initialData) {
      setFormData(initialData);
    } else {
      setFormData({
        name: '',
        sku: '',
        category: CATEGORIES[0],
        price: 0,
        quantity: 0,
        minThreshold: 10,
        supplier: '',
        imageUrl: 'https://picsum.photos/200/200'
      });
    }
  }, [initialData, isOpen]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Basic Validation
    if (!formData.name || !formData.price || !formData.sku) {
      alert("Please fill in all required fields");
      return;
    }

    if (initialData && initialData.id) {
      updateProduct(initialData.id, formData);
    } else {
      addProduct(formData as any);
    }
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
          <h3 className="text-xl font-bold text-slate-800">
            {initialData ? 'Edit Product' : 'Add New Product'}
          </h3>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700">Product Name *</label>
              <input 
                required
                type="text" 
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none"
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700">SKU (Stock Keeping Unit) *</label>
              <input 
                required
                type="text" 
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none font-mono"
                value={formData.sku}
                onChange={e => setFormData({...formData, sku: e.target.value})}
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700">Category</label>
              <select 
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none bg-white"
                value={formData.category}
                onChange={e => setFormData({...formData, category: e.target.value})}
              >
                {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700">Supplier</label>
              <input 
                type="text" 
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none"
                value={formData.supplier}
                onChange={e => setFormData({...formData, supplier: e.target.value})}
              />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700">Price ($) *</label>
              <input 
                required
                type="number" 
                min="0"
                step="0.01"
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none"
                value={formData.price}
                onChange={e => setFormData({...formData, price: parseFloat(e.target.value)})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700">Current Quantity</label>
              <input 
                type="number" 
                min="0"
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none"
                value={formData.quantity}
                onChange={e => setFormData({...formData, quantity: parseInt(e.target.value)})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700">Low Stock Alert at</label>
              <input 
                type="number" 
                min="0"
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none"
                value={formData.minThreshold}
                onChange={e => setFormData({...formData, minThreshold: parseInt(e.target.value)})}
              />
            </div>
          </div>

           {/* Image Upload Simulation */}
           <div className="space-y-2">
              <label className="text-sm font-medium text-slate-700">Product Image URL</label>
              <div className="flex gap-4">
                <input 
                  type="text" 
                  className="flex-1 px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none"
                  value={formData.imageUrl}
                  onChange={e => setFormData({...formData, imageUrl: e.target.value})}
                />
                <div className="w-10 h-10 rounded-lg bg-slate-100 overflow-hidden border border-slate-200">
                  {formData.imageUrl && <img src={formData.imageUrl} className="w-full h-full object-cover" alt="Preview" />}
                </div>
              </div>
            </div>

          <div className="flex justify-end gap-4 pt-4 border-t border-slate-100">
            <button 
              type="button" 
