import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { AuthContextType, User } from '../types';

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('stockify_user');
    return saved ? JSON.parse(saved) : null;
  });

  useEffect(() => {
    if (user) {
      localStorage.setItem('stockify_user', JSON.stringify(user));
    } else {
      localStorage.removeItem('stockify_user');
    }
  }, [user]);

  const login = async (email: string, pass: string): Promise<boolean> => {
    // Mock authentication delay
    await new Promise(resolve => setTimeout(resolve, 800));

    if (email === 'admin@stockify.com' && pass === 'admin123') {
      setUser({
        id: 'admin-1',
        name: 'Admin User',
        email,
        role: 'ADMIN'
      });
      return true;
    }

    if (email === 'staff@stockify.com' && pass === 'staff123') {
      setUser({
        id: 'staff-1',
        name: 'Staff Member',
        email,
        role: 'STAFF'
      });
      return true;
    }

    return false;
  };

  const logout = () => {
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

