import React, { useState } from 'react';
import { useSuppliers } from '../contexts/SupplierContext';
import { useAuth } from '../contexts/AuthContext';
import { Supplier } from '../types';
import { 
  Search, Plus, Trash2, Edit2, MapPin, Phone, Mail, Building 
} from 'lucide-react';

const SuppliersTable = () => {
  const { suppliers, deleteSupplier, addSupplier, updateSupplier } = useSuppliers();
  const { user } = useAuth();
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingSupplier, setEditingSupplier] = useState<Supplier | undefined>(undefined);

  // Form State
  const [formData, setFormData] = useState<Partial<Supplier>>({});

  const filteredSuppliers = suppliers.filter(s => 
    s.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.contactPerson.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleEdit = (supplier: Supplier) => {
    setEditingSupplier(supplier);
    setFormData(supplier);
    setIsModalOpen(true);
  };

  const handleAdd = () => {
    setEditingSupplier(undefined);
    setFormData({});
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
    if (confirm('Are you sure you want to delete this supplier? This may affect products linked to them.')) {
      deleteSupplier(id);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email) return;

    if (editingSupplier && editingSupplier.id) {
      updateSupplier(editingSupplier.id, formData);
    } else {
      addSupplier(formData as any);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
