export const ViewState = {
  LOGIN: 'LOGIN',
  DASHBOARD: 'DASHBOARD',
  INVENTORY: 'INVENTORY',
  SUPPLIERS: 'SUPPLIERS',
  SETTINGS: 'SETTINGS'
