import React, { createContext, useContext, useState, useEffect, useMemo } from 'react';
import { MOCK_PRODUCTS } from '../constants';

const StockContext = createContext(undefined);

export const StockProvider = ({ children }) => {
  // Initialize with mock data
  const [products, setProducts] = useState(() => {
    const saved = localStorage.getItem('stockify_products');
    return saved ? JSON.parse(saved) : MOCK_PRODUCTS;
  });

  // Persist to local storage
  useEffect(() => {
    localStorage.setItem('stockify_products', JSON.stringify(products));
  }, [products]);

  const addProduct = (newProductData) => {
    const newProduct = {
      ...newProductData,
      id: Math.random().toString(36).substr(2, 9),
      lastUpdated: new Date().toISOString()
    };
    setProducts(prev => [newProduct, ...prev]);
  };

  const updateProduct = (id, updates) => {
    setProducts(prev => prev.map(p => 
      p.id === id ? { ...p, ...updates, lastUpdated: new Date().toISOString() } : p
    ));
  };

  const deleteProduct = (id) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const stats = useMemo(() => {
    return {
      totalValue: products.reduce((acc, curr) => acc + (curr.price * curr.quantity), 0),
      lowStockCount: products.filter(p => p.quantity <= p.minThreshold).length,
      totalItems: products.reduce((acc, curr) => acc + curr.quantity, 0),
      categoriesCount: new Set(products.map(p => p.category)).size
    };
  }, [products]);

  return (
    <StockContext.Provider value={{ products, addProduct, updateProduct, deleteProduct, stats }}>
      {children}
    </StockContext.Provider>
  );
};

export const useStock = () => {
  const context = useContext(StockContext);
  if (context === undefined) {
    throw new Error('useStock must be used within a StockProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect } from 'react';

const AuthContext = createContext(undefined);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(() => {
    const saved = localStorage.getItem('stockify_user');
    return saved ? JSON.parse(saved) : null;
  });

  useEffect(() => {
    if (user) {
      localStorage.setItem('stockify_user', JSON.stringify(user));
    } else {
      localStorage.removeItem('stockify_user');
    }
  }, [user]);

  const login = async (email, pass) => {
    // Mock authentication delay
    await new Promise(resolve => setTimeout(resolve, 800));

    if (email === 'admin@stockify.com' && pass === 'admin123') {
      setUser({
        id: 'admin-1',
        name: 'Admin User',
        email,
        role: 'ADMIN'
      });
      return true;
    }

    if (email === 'staff@stockify.com' && pass === 'staff123') {
      setUser({
        id: 'staff-1',
        name: 'Staff Member',
        email,
        role: 'STAFF'
      });
      return true;
    }

    return false;
  };

  const logout = () => {
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
