                <p className="text-slate-500 mt-1">staff@stockify.com</p>
                <p className="text-slate-400">staff123</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { StockProvider } from './contexts/StockContext';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { SupplierProvider } from './contexts/SupplierContext';
import { ViewState } from './types';
import { APP_CONFIG } from './constants';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import InventoryTable from './components/InventoryTable';
import SuppliersTable from './components/SuppliersTable';
import Login from './components/Login';

const SettingsView = () => (
  <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-500">
    <h2 className="text-2xl font-bold text-slate-800">System Settings</h2>
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
      <h3 className="text-lg font-semibold text-slate-800 mb-4">Application Configuration</h3>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
         <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">App Name</label>
            <input disabled value={APP_CONFIG.appName} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-slate-500" />
         </div>
         <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">Primary Currency</label>
            <input disabled value={APP_CONFIG.currency} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-slate-500" />
         </div>
      </div>
      <div className="mt-6 p-4 bg-yellow-50 text-yellow-800 rounded-lg text-sm border border-yellow-100">
        Note: Global configuration is managed via <code>constants.ts</code> in the source code.
      </div>
    </div>
  </div>
);

const AppContent = () => {
  const { user } = useAuth();
  const [currentView, setCurrentView] = useState(ViewState.DASHBOARD);

  useEffect(() => {
    if (user) {
      document.title = `${APP_CONFIG.appName} | ${currentView.charAt(0) + currentView.slice(1).toLowerCase()}`;
    } else {
      document.title = `${APP_CONFIG.appName} | Login`;
    }
  }, [currentView, user]);

  if (!user) {
    return <Login />;
  }

  return (
    <Layout currentView={currentView} onNavigate={setCurrentView}>
      {currentView === ViewState.DASHBOARD && <Dashboard />}
      {currentView === ViewState.INVENTORY && <InventoryTable />}
      {currentView === ViewState.SUPPLIERS && <SuppliersTable />}
      {currentView === ViewState.SETTINGS && <SettingsView />}
    </Layout>
  );
};

export default function App() {
  return (
    <AuthProvider>
      <SupplierProvider>
        <StockProvider>
          <AppContent />
        </StockProvider>
      </SupplierProvider>
    </AuthProvider>
  );
}

import React from 'react';
